// Extract and clean email data for AI processing
const items = $input.all();
const processedEmails = [];

for (const item of items) {
  const email = item.json;

  // ============================================
  // SAFELY EXTRACT HEADERS (handles all formats)
  // ============================================

  function safeString(value) {
    if (!value) return '';
    if (typeof value === 'string') return value;
    if (Array.isArray(value)) return value.map(v => safeString(v)).join(', ');
    if (typeof value === 'object') {
      // Gmail sometimes returns { name: "John", email: "user@example.com" }
      if (value.value) return safeString(value.value);
      if (value.text) return safeString(value.text);
      if (value.email && value.name) return `${value.name} <${value.email}>`;
      if (value.email) return value.email;
      if (value.address) return value.address;
      return JSON.stringify(value);
    }
    return String(value);
  }

  function getHeader(headers, name) {
    if (!headers || !Array.isArray(headers)) return '';
    const found = headers.find(h => 
      h && h.name && h.name.toLowerCase() === name.toLowerCase()
    );
    return found ? safeString(found.value) : '';
  }

  // Try multiple Gmail node output formats
  let fromHeader = '';
  let subjectHeader = '';
  let dateHeader = '';
  let toHeader = '';
  let ccHeader = '';
  let replyToHeader = '';

  // Format 1: Gmail Trigger v1 (flat fields)
  if (email.from) {
    fromHeader = safeString(email.from);
    subjectHeader = safeString(email.subject || '');
    dateHeader = safeString(email.date || email.internalDate || '');
    toHeader = safeString(email.to || '');
    ccHeader = safeString(email.cc || '');
    replyToHeader = safeString(email.replyTo || '');
  }

  // Format 2: Gmail API raw (payload.headers array)
  if (email.payload && email.payload.headers) {
    fromHeader = fromHeader || getHeader(email.payload.headers, 'from');
    subjectHeader = subjectHeader || getHeader(email.payload.headers, 'subject');
    dateHeader = dateHeader || getHeader(email.payload.headers, 'date');
    toHeader = toHeader || getHeader(email.payload.headers, 'to');
    ccHeader = ccHeader || getHeader(email.payload.headers, 'cc');
    replyToHeader = replyToHeader || getHeader(email.payload.headers, 'reply-to');
  }

  // Format 3: Some Gmail nodes use headers directly
  if (email.headers) {
    const h = email.headers;
    fromHeader = fromHeader || safeString(h.from || h.From || '');
    subjectHeader = subjectHeader || safeString(h.subject || h.Subject || '');
    dateHeader = dateHeader || safeString(h.date || h.Date || '');
    toHeader = toHeader || safeString(h.to || h.To || '');
    ccHeader = ccHeader || safeString(h.cc || h.Cc || '');
  }

  // Format 4: labelIds at top level (Gmail Trigger v2)
  if (!fromHeader && email.labelIds) {
    fromHeader = safeString(email.from || '');
    subjectHeader = safeString(email.subject || '');
  }

  // ============================================
  // PARSE SENDER NAME AND EMAIL
  // ============================================
  let senderName = '';
  let senderEmail = '';
  let senderDomain = '';

  // Ensure fromHeader is definitely a string before regex
  fromHeader = String(fromHeader || '');
  subjectHeader = String(subjectHeader || '');

  try {
    // Try "Name <email>" format
    const senderMatch = fromHeader.match(/^"?([^"<]+)"?\s*<?([^>]*)>?$/);
    if (senderMatch && senderMatch[2]) {
      senderName = senderMatch[1].trim();
      senderEmail = senderMatch[2].trim();
    } else if (fromHeader.includes('@')) {
      // Just an email address
      senderEmail = fromHeader.trim();
      senderName = senderEmail.split('@')[0];
    } else {
      senderName = fromHeader;
      senderEmail = fromHeader;
    }

    senderDomain = senderEmail.includes('@') ? senderEmail.split('@')[1] : '';
  } catch (e) {
    senderName = fromHeader;
    senderEmail = fromHeader;
    senderDomain = '';
  }

  // ============================================
  // EXTRACT BODY TEXT
  // ============================================
  let bodyText = '';

  // Try direct text fields first (most Gmail trigger versions)
  if (email.text) {
    bodyText = safeString(email.text);
  } else if (email.textPlain) {
    bodyText = safeString(email.textPlain);
  } else if (email.snippet) {
    bodyText = safeString(email.snippet);
  } else if (email.textHtml) {
    bodyText = safeString(email.textHtml);
  }

  // Try payload body
  if (!bodyText && email.payload) {
    if (email.payload.body && email.payload.body.data) {
      try {
        bodyText = Buffer.from(email.payload.body.data, 'base64').toString('utf-8');
      } catch (e) {}
    }

    // Try multipart
    if (!bodyText && email.payload.parts) {
      for (const part of email.payload.parts) {
        if (part.mimeType === 'text/plain' && part.body && part.body.data) {
          try {
            bodyText = Buffer.from(part.body.data, 'base64').toString('utf-8');
            break;
          } catch (e) {}
        }
      }
      // Fallback to HTML part
      if (!bodyText) {
        for (const part of email.payload.parts) {
          if (part.mimeType === 'text/html' && part.body && part.body.data) {
            try {
              bodyText = Buffer.from(part.body.data, 'base64').toString('utf-8');
              break;
            } catch (e) {}
          }
        }
      }
    }
  }

  // Use snippet as last resort
  if (!bodyText && email.snippet) {
    bodyText = safeString(email.snippet);
  }

  // Clean body text
  bodyText = String(bodyText || '')
    .replace(/<[^>]+>/g, ' ')       // Strip HTML
    .replace(/\r\n/g, '\n')         // Normalize newlines
    .replace(/\n{3,}/g, '\n\n')     // Max 2 newlines
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')           // Collapse whitespace
    .trim()
    .substring(0, 3000);            // Limit for AI

  // ============================================
  // DETECT FLAGS
  // ============================================
  const hasAttachments = !!(
    (email.payload && email.payload.parts && email.payload.parts.some(p => p.filename && p.filename.length > 0)) ||
    email.attachments ||
    (Array.isArray(email.attachments) && email.attachments.length > 0)
  );

  const isReply = subjectHeader.toLowerCase().startsWith('re:');
  const isForward = subjectHeader.toLowerCase().startsWith('fwd:') || subjectHeader.toLowerCase().startsWith('fw:');

  // ============================================
  // BUILD OUTPUT
  // ============================================
  processedEmails.push({
    json: {
      // Gmail metadata
      gmailId: email.id || email.messageId || '',
      threadId: email.threadId || '',
      labelIds: email.labelIds || [],

      // Parsed fields
      from: fromHeader,
      senderName: senderName,
      senderEmail: senderEmail,
      senderDomain: senderDomain,
      to: toHeader,
      cc: ccHeader,
      replyTo: replyToHeader || senderEmail,
      subject: subjectHeader,
      date: dateHeader,

      // Content
      bodyText: bodyText,
      bodyPreview: bodyText.substring(0, 300),

      // Flags
      hasAttachments: hasAttachments,
      isReply: isReply,
      isForward: isForward,

      // Processing
      processedAt: new Date().toISOString()
    }
  });
}

if (processedEmails.length === 0) {
  return [{ json: { error: 'No emails to process', processedAt: new Date().toISOString() } }];
}

return processedEmails;

