// Extract AI classification from response
const emailData = $('🔧 Extract Email Data').item.json;
const rawAiOutput = $json;

let classData = {};

function extractJSON(str) {
  if (typeof str !== 'string') return null;
  let cleaned = str.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  try { return JSON.parse(cleaned); } catch (e) {
    const match = cleaned.match(/\{[\s\S]*"category"\s*:[\s\S]*\}/);
    if (match) { try { return JSON.parse(match[0]); } catch (e2) { return null; } }
    return null;
  }
}

function findAIResponse(obj, depth = 0) {
  if (depth > 5 || !obj || typeof obj !== 'object') return null;
  if (obj.category && typeof obj.category === 'string') return obj;
  const props = ['output', 'text', 'message', 'content', 'response', 'result', 'data', 'json', 'kwargs', 'lc_kwargs'];
  for (const prop of props) {
    if (obj[prop] !== undefined) {
      if (typeof obj[prop] === 'string') { const p = extractJSON(obj[prop]); if (p && p.category) return p; }
      else if (typeof obj[prop] === 'object') { const f = findAIResponse(obj[prop], depth + 1); if (f) return f; }
    }
  }
  for (const key of Object.keys(obj)) {
    if (props.includes(key)) continue;
    const val = obj[key];
    if (typeof val === 'string' && val.includes('"category"')) { const p = extractJSON(val); if (p && p.category) return p; }
    else if (typeof val === 'object' && val !== null) { const f = findAIResponse(val, depth + 1); if (f) return f; }
  }
  return null;
}

try {
  if (rawAiOutput && rawAiOutput.category) { classData = rawAiOutput; }
  else { const found = findAIResponse(rawAiOutput); if (found) classData = found; }
  if (!classData.category) { const s = JSON.stringify(rawAiOutput); const p = extractJSON(s); if (p && p.category) classData = p; }
} catch (error) {}

const validCategories = ['urgent', 'action_required', 'follow_up', 'newsletter', 'automated', 'spam_promo'];

if (!classData.category || !validCategories.includes(classData.category)) {
  classData = {
    category: 'follow_up',
    priority: 2,
    confidence: 0.5,
    reason: 'Could not parse AI response — defaulting to follow_up',
    summary: emailData.bodyPreview || 'Email content',
    keyAction: 'Review manually',
    replyDraft: '',
    replySubject: '',
    suggestedLabel: '💬 Follow-up',
    shouldAutoArchive: false,
    sentimentTone: 'neutral'
  };
}

return {
  json: {
    // Email data
    gmailId: emailData.gmailId,
    threadId: emailData.threadId,
    from: emailData.from,
    senderName: emailData.senderName,
    senderEmail: emailData.senderEmail,
    senderDomain: emailData.senderDomain,
    to: emailData.to,
    subject: emailData.subject,
    date: emailData.date,
    bodyPreview: emailData.bodyPreview,
    hasAttachments: emailData.hasAttachments,
    isReply: emailData.isReply,
    replyTo: emailData.replyTo,

    // AI classification
    category: classData.category,
    priority: classData.priority || 2,
    confidence: parseFloat(classData.confidence) || 0,
    reason: classData.reason || '',
    summary: classData.summary || '',
    keyAction: classData.keyAction || '',
    replyDraft: classData.replyDraft || '',
    replySubject: classData.replySubject || `Re: ${emailData.subject}`,
    suggestedLabel: classData.suggestedLabel || '💬 Follow-up',
    shouldAutoArchive: classData.shouldAutoArchive === true,
    sentimentTone: classData.sentimentTone || 'neutral',

    // Meta
    processedAt: new Date().toISOString()
  }
};

// Merge all paths back for logging
const item = $input.all()[0].json;

// Try to get original classification data from the appropriate upstream node
let classificationData = {};

try {
  classificationData = $('🎯 Extract Classification').item.json;
} catch (e) {
  classificationData = item;
}

return {
  json: {
    // For Google Sheets logging
    Date: classificationData.date || new Date().toISOString(),
    From: classificationData.from || '',
    Subject: classificationData.subject || '',
    Category: classificationData.category || '',
    Priority: classificationData.priority || '',
    Confidence: classificationData.confidence || '',
    Reason: classificationData.reason || '',
    Summary: classificationData.summary || '',
    'Key Action': classificationData.keyAction || '',
    'Has Reply Draft': classificationData.replyDraft ? 'Yes' : 'No',
    Sentiment: classificationData.sentimentTone || '',
    'Auto Archive': classificationData.shouldAutoArchive ? 'Yes' : 'No',
    'Gmail ID': classificationData.gmailId || '',
    'Processed At': classificationData.processedAt || new Date().toISOString()
  }
};
